import pickle
import base64
from google.cloud import pubsub_v1

def process_pubsub_message(request):
    """Process Pub/Sub messages containing serialized Python objects."""
    
    # Extract the Pub/Sub message from the request
    envelope = request.get_json()
    pubsub_message = envelope['message']
    
    # Decode the Base64-encoded data
    encoded_data = pubsub_message.get('data')
    decoded_data = base64.b64decode(encoded_data)
    
    # Deserialize the Python object using pickle.loads()
    python_object = pickle.loads(decoded_data)
    
    # Process the batch job (example: print the object)
    print(python_object)
    
    return 'Processed message', 200